import React from 'react';

const ProductionScore = ({ data }: { data: any }) => {
    if (!data) return null;

    const score = data.readiness_score;
    const isAlert = data.status === "RED";

    return (
        <div className="flex flex-col items-center justify-center py-6">
            <div className="relative flex items-center justify-center w-56 h-56">
                {/* SVG Geometric Gauge */}
                <svg className="w-full h-full transform -rotate-90 animate-fade-in" viewBox="0 0 100 100">
                    {/* Background Circle */}
                    <circle
                        cx="50" cy="50" r="48"
                        fill="none"
                        stroke="#121212"
                        strokeWidth="1"
                        strokeDasharray="2 4"
                    />
                    {/* Track */}
                    <circle cx="50" cy="50" r="45" fill="none" stroke="#1A1A1A" strokeWidth="0.5" />
                    {/* Progress */}
                    <circle
                        cx="50" cy="50" r="45"
                        fill="none"
                        stroke={isAlert ? "#FF3B30" : "#FFFFFF"}
                        strokeWidth="2"
                        strokeDasharray={`${(score / 100) * 283} 283`}
                        className="transition-all duration-[1500ms] cubic-bezier(0.4, 0, 0.2, 1)"
                    />

                    {/* Decorative Geometric Notches */}
                    {[0, 90, 180, 270].map((angle) => (
                        <rect
                            key={angle}
                            x="49.5" y="2" width="1" height="4"
                            fill={angle === 0 ? "#FF3B30" : "#333"}
                            transform={`rotate(${angle}, 50, 50)`}
                        />
                    ))}
                </svg>

                {/* Central Value */}
                <div className="absolute flex flex-col items-center">
                    <span className="text-6xl font-black tracking-tighter text-white drop-shadow-[0_0_15px_rgba(255,255,255,0.2)]">
                        {score}
                    </span>
                    <div className="flex items-center space-x-2 mt-1">
                        <div className={`w-1 h-1 ${isAlert ? 'bg-[#FF3B30]' : 'bg-white'}`} />
                        <span className={`nothing-text-label ${isAlert ? 'text-[#FF3B30]' : 'text-white'}`}>
                            {data.status}
                        </span>
                    </div>
                </div>
            </div>

            <div className="mt-10 w-full text-center">
                <p className="text-[10px] text-gray-700 uppercase leading-relaxed tracking-widest font-bold">
                    System.Stability: 0.992 Prob<br />
                    Verification.Logic: Lifelines.Cox
                </p>
                <div className="mt-4 flex justify-center space-x-1">
                    {[...Array(24)].map((_, i) => (
                        <div key={i} className={`w-[2px] h-[2px] rounded-full ${i < 18 ? 'bg-white' : 'bg-gray-900'}`} />
                    ))}
                </div>
            </div>
        </div>
    );
};

export default ProductionScore;
